import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.wfnuidXa.js";const _=JSON.parse('{"title":"规则编写","description":"","frontmatter":{},"headers":[],"relativePath":"rules/authoring.md","filePath":"rules/authoring.md","lastUpdated":1780989355000}'),o={name:"rules/authoring.md"};function i(l,t,n,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="规则编写" tabindex="-1">规则编写 <a class="header-anchor" href="#规则编写" aria-label="Permalink to &quot;规则编写&quot;">​</a></h1><p>LiteWaf 规则用于描述请求检测条件和处置方式。规则应保持可解释、可回滚，并避免依赖远程执行逻辑。</p><h2 id="基础字段" tabindex="-1">基础字段 <a class="header-anchor" href="#基础字段" aria-label="Permalink to &quot;基础字段&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td>规则的可读名称</td></tr><tr><td>目标</td><td>URI、Header、Query、Body、上传元数据等检测目标</td></tr><tr><td>表达式</td><td>匹配条件</td></tr><tr><td>动作</td><td>记录、拦截或计分</td></tr><tr><td>分值</td><td>参与策略阈值判断</td></tr><tr><td>状态</td><td>是否启用</td></tr></tbody></table><h2 id="编写建议" tabindex="-1">编写建议 <a class="header-anchor" href="#编写建议" aria-label="Permalink to &quot;编写建议&quot;">​</a></h2><ul><li>先用记录或低风险策略验证命中情况，再切换到拦截。</li><li>为误报风险较高的规则设置清晰名称和说明。</li><li>将通用规则和业务专用规则分开维护。</li><li>发布前使用预览确认规则会进入目标站点策略。</li></ul><h2 id="不支持的边界" tabindex="-1">不支持的边界 <a class="header-anchor" href="#不支持的边界" aria-label="Permalink to &quot;不支持的边界&quot;">​</a></h2><p>当前阶段不执行第三方远程代码，不把任意 Lua 插件作为社区规则动态运行，也不在 Gateway 请求热路径进行远程签名校验。</p><p>详细字段和示例见 <a href="https://github.com/newz-max/litewaf-api/blob/master/doc/%E8%A7%84%E5%88%99%E7%BC%96%E5%86%99%E6%8C%87%E5%8D%97.md" target="_blank" rel="noreferrer"><code>litewaf-api/doc/规则编写指南.md</code></a>。</p>',9)])])}const p=a(o,[["render",i]]);export{_ as __pageData,p as default};
